import{_ as t,o as a,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"99. Ohs Risk Management","description":"","frontmatter":{"title":"99. Ohs Risk Management","eba":"Allied Health Professionals 2021-2026","topics":["consultation","ohs"]},"headers":[],"relativePath":"ebas/allied-health/ohs/99-ohs-risk-management.md","filePath":"ebas/allied-health/ohs/99-ohs-risk-management.md"}'),o={name:"ebas/allied-health/ohs/99-ohs-risk-management.md"};function r(i,e,l,h,p,c){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_99-ohs-risk-management" tabindex="-1">99. Ohs Risk Management <a class="header-anchor" href="#_99-ohs-risk-management" aria-label="Permalink to &quot;99. Ohs Risk Management&quot;">​</a></h1><p><strong>99.1</strong> Those covered by this Agreement will take a pro-active approach to the prevention and management of workplace injuries to the highest level of protection reasonably practicable in the circumstances, and to the achievement of a reduction in workplace injuries through the implementation of risk management systems incorporating hazard identification, risk assessment and control, and safe work practices.</p><p><strong>99.2</strong> The Employer will implement the hierarchy of controls to control hazards and will eliminate the hazard at the source wherever practicable.</p><p><strong>99.3</strong> Those covered by this Agreement recognise that consultation with Employees and their representatives is crucial to achieving a healthy and safe work environment. To this end, Employers will:</p><p><strong>(a)</strong> consult with Employees covered by this Agreement and their representatives around matters relating to health and safety in the workplace; and</p><p><strong>(b)</strong> ensure managers of Employees receive adequate education and support to ensure the following can occur:</p><p><strong>(i)</strong> the assessment of OHS risks;</p><p><strong>(ii)</strong> the undertaking of OHS incident investigations; and</p><p><strong>(iii)</strong> Consultation with Employees over OHS issues.</p><p><strong>99.4</strong> This Agreement recognises that hazards include, but are not limited to:</p><p><strong>(a)</strong> safe patient and manual handling;</p><p><strong>(b)</strong> occupational violence and aggression;</p><p><strong>(c)</strong> circumstances that give rise to adverse effects on psychological health, including bullying, workplace stress and fatigue;</p><p><strong>(d)</strong> unsafe design and layout of health workplaces;</p><p><strong>(e)</strong> slips, trips and falls;</p><p><strong>(f)</strong> blood borne and other infectious diseases;</p><p><strong>(g)</strong> sharps; and</p><p><strong>(h)</strong> hazardous substances.</p><p><strong>99.5</strong> The Employer shall provide such information, education, training and supervision to all Employees of the Employer required to enable them to perform their work in a manner which is safe and without risks to health. This shall occur on a regular basis as required to enable Employees to remain informed in relation to health and safety hazards, policies and procedures.</p>',19)])])}const m=t(o,[["render",r]]);export{d as __pageData,m as default};
